'use client';

import React, { forwardRef } from 'react';
import { useTheme } from '../providers/ThemeProvider';
import { neoBrutalism } from '../styles/tokens';

export type ButtonVariant = 'primary' | 'secondary' | 'outline';
export type ButtonSize = 'sm' | 'md' | 'lg';

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  /** Visual variant */
  variant?: ButtonVariant;
  /** Size preset */
  size?: ButtonSize;
  /** Full width button */
  fullWidth?: boolean;
  /** Loading state */
  loading?: boolean;
}

const sizeStyles: Record<ButtonSize, React.CSSProperties> = {
  sm: { padding: '8px 16px', fontSize: '14px' },
  md: { padding: '12px 24px', fontSize: '16px' },
  lg: { padding: '16px 32px', fontSize: '18px' },
};

/**
 * Button component with Neo Brutalism styling.
 *
 * - Primary: 0px border-radius, min 2px solid border, 4px hard shadow
 * - Secondary: subtle 4px border-radius, min 2px border, 4px hard shadow
 * - Outline: transparent background, min 2px border, 4px hard shadow
 *
 * Supports dark/light theme variants via useTheme hook.
 *
 * @see Requirements 1.1, 1.2
 */
export const Button = forwardRef<HTMLButtonElement, ButtonProps>(
  (
    {
      variant = 'primary',
      size = 'md',
      fullWidth = false,
      loading = false,
      disabled,
      style,
      children,
      ...props
    },
    ref
  ) => {
    const { mode, colors } = useTheme();
    const shadowColor = neoBrutalism.shadows.color[mode];

    const baseStyles: React.CSSProperties = {
      display: 'inline-flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '8px',
      fontFamily: neoBrutalism.typography.body.family,
      fontWeight: 700,
      cursor: disabled || loading ? 'not-allowed' : 'pointer',
      transition: 'transform 0.1s ease, box-shadow 0.1s ease',
      opacity: disabled ? 0.6 : 1,
      width: fullWidth ? '100%' : undefined,
      ...sizeStyles[size],
    };

    const variantStyles: Record<ButtonVariant, React.CSSProperties> = {
      primary: {
        backgroundColor: colors.accentCyan,
        color: mode === 'dark' ? '#0A0A0A' : '#FFFFFF',
        border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
        borderRadius: neoBrutalism.borders.radius.none,
        boxShadow: `${neoBrutalism.shadows.offset.md} ${shadowColor}`,
      },
      secondary: {
        backgroundColor: colors.accentPurple,
        color: '#FFFFFF',
        border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
        borderRadius: neoBrutalism.borders.radius.subtle,
        boxShadow: `${neoBrutalism.shadows.offset.md} ${shadowColor}`,
      },
      outline: {
        backgroundColor: 'transparent',
        color: colors.textPrimary,
        border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
        borderRadius: neoBrutalism.borders.radius.none,
        boxShadow: `${neoBrutalism.shadows.offset.md} ${shadowColor}`,
      },
    };

    const combinedStyle: React.CSSProperties = {
      ...baseStyles,
      ...variantStyles[variant],
      ...style,
    };

    return (
      <button
        ref={ref}
        disabled={disabled || loading}
        style={combinedStyle}
        aria-busy={loading || undefined}
        {...props}
      >
        {loading && (
          <span
            aria-hidden="true"
            style={{
              width: '16px',
              height: '16px',
              border: '2px solid currentColor',
              borderTopColor: 'transparent',
              borderRadius: '50%',
              animation: 'spin 0.6s linear infinite',
            }}
          />
        )}
        {children}
      </button>
    );
  }
);

Button.displayName = 'Button';

