              left: 0,
              right: 0,
              padding: '32px 24px',
            }}
          >
            <h3
              data-name="true"
              style={{
                fontSize: '22px',
                fontWeight: 700,
                margin: '0 0 6px 0',
                color: '#ffffff',
                transition: 'text-shadow 0.3s ease',
              }}
            >
              {cls.name}
            </h3>
            <span
              style={{
                fontSize: '11px',
                fontWeight: 500,
                letterSpacing: '0.15em',
                textTransform: 'uppercase',
                color: '#00d4ff',
              }}
            >
              {cls.role}
            </span>
          </div>
        </div>
      ))}
    </div>
  </div>
</section>

